class Solution:
    def maximumBeauty(self, flowers, newFlowers, target, full, partial):
        n = len(flowers)
        best = 0

        def dfs(idx, remaining, current):
            nonlocal best
            if idx == n:
                complete = sum(1 for v in current if v >= target)
                incomplete = [v for v in current if v < target]
                min_incomplete = min(incomplete) if incomplete else 0
                beauty = complete * full + min_incomplete * partial
                if beauty > best:
                    best = beauty
                return
            base = flowers[idx]
            max_add = min(remaining, target - base) if base < target else 0
            for add in range(0, max_add + 1):
                dfs(idx + 1, remaining - add, current + [base + add])

        dfs(0, min(newFlowers, n * target), [])
        return best

