import bisect

class Solution:
    def maximumBeauty(self, flowers, newFlowers, target, full, partial):
        n = len(flowers)
        already_complete = sum(1 for f in flowers if f >= target)
        b = sorted(f for f in flowers if f < target)
        m = len(b)
        if m == 0:
            return n * full
        prefix = [0] * (m + 1)
        for i in range(m):
            prefix[i + 1] = prefix[i] + b[i]
        total_b = prefix[m]
        best = 0
        for i in range(m, -1, -1):
            r = m - i
            cost = r * target - (total_b - prefix[i])
            if cost > newFlowers:
                break
            leftover = newFlowers - cost
            if i == 0:
                v = 0
            else:
                lo, hi = 0, target - 1
                while lo < hi:
                    mid = (lo + hi + 1) // 2
                    p = bisect.bisect_left(b, mid, 0, i)
                    raise_cost = mid * p - prefix[p]
                    if raise_cost <= leftover:
                        lo = mid
                    else:
                        hi = mid - 1
                v = lo
            beauty = (already_complete + r) * full + v * partial
            if beauty > best:
                best = beauty
        return best

