var maximumBeauty = function(flowers, newFlowers, target, full, partial) {
    const n = flowers.length;
    let alreadyComplete = 0;
    for (const f of flowers) if (f >= target) alreadyComplete++;
    const b = flowers.filter(f => f < target).sort((a, c) => a - c);
    const m = b.length;
    if (m === 0) return n * full;
    const prefix = new Array(m + 1).fill(0);
    for (let i = 0; i < m; i++) prefix[i + 1] = prefix[i] + b[i];
    const totalB = prefix[m];

    function bisectLeft(value, hiIdx) {
        let lo = 0, hi = hiIdx;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (b[mid] < value) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }

    let best = 0;
    for (let i = m; i >= 0; i--) {
        const r = m - i;
        const cost = r * target - (totalB - prefix[i]);
        if (cost > newFlowers) break;
        const leftover = newFlowers - cost;
        let v;
        if (i === 0) {
            v = 0;
        } else {
            let lo = 0, hi = target - 1;
            while (lo < hi) {
                const mid = Math.floor((lo + hi + 1) / 2);
                const p = bisectLeft(mid, i);
                const raiseCost = mid * p - prefix[p];
                if (raiseCost <= leftover) lo = mid;
                else hi = mid - 1;
            }
            v = lo;
        }
        const beauty = (alreadyComplete + r) * full + v * partial;
        if (beauty > best) best = beauty;
    }
    return best;
};
